test('calls logger', () => {
  const spy = jest.spyOn(console, 'log');
  greet('Ada');
  expect(spy).toHaveBeenCalledWith('Hello, Ada');
});

import org.mockito.Mockito;
Logger spy = Mockito.spy(new Logger());
greet(spy, "Ada");
Mockito.verify(spy).log("Hello, Ada");

CREATE TABLE call_spy (
  call_id INT AUTO_INCREMENT PRIMARY KEY,
  function_name VARCHAR(255),
  args TEXT
);
INSERT INTO call_spy (function_name, args) VALUES ('greet', 'Ada');
